class Solution:
    def findMaximumLength(self, nums: List[int]) -> int:
        n = len(nums)
        total = sum(nums)
        res = 0
        curr_sum = 0
        for i in range(n):
            curr_sum += nums[i]
            if curr_sum >= total - curr_sum:
                res = i + 1
                total = curr_sum
                curr_sum = 0
        return res
